#include <stdio.h>
#define MOD 1000000007
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int H, W;
        scanf("%d %d", &H, &W);
        int B[H][W];
        for (int i = 0; i < H; i++) {
            for (int j = 0; j < W; j++) {
                scanf("%d", &B[i][j]);
            }
        }
        long long dp[H + 1][W + 1];
        for (int i = 0; i <= H; i++) {
            for (int j = 0; j <= W; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 0; i < H; i++) {
            for (int j = 0; j < W; j++) {
                if (B[i][j] == 1) {
                    dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j]) % MOD;
                } else {
                    dp[i + 1][j + 1] = (dp[i + 1][j + 1] + dp[i][j] * 3) % MOD;
                }
            }
        }
        printf("%lld\n", dp[H][W]);
    }
    return 0;
}

