let idx = 0;
const MOD = 1000000007;
const T = parseInt(lines[idx++]);
for (let i = 0; i < T; i++) {
    const [H, W] = lines[idx++].split(' ').map(Number);
    const B = [];
    for (let j = 0; j < H; j++) {
        B.push(lines[idx++].split(' ').map(Number));
    }
    const dp = Array(H + 1).fill(0).map(() => Array(W + 1).fill(0));
    dp[0][0] = 1;
    for (let j = 0; j < H; j++) {
        for (let k = 0; k < W; k++) {
            if (B[j][k] === 1) {
                dp[j + 1][k + 1] = (dp[j + 1][k + 1] + dp[j][k]) % MOD;
            } else {
                dp[j + 1][k + 1] = (dp[j + 1][k + 1] + dp[j][k] * 3) % MOD;
            }
        }
    }
    console.log(dp[H][W]);
}
